import { Component, OnInit } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { FashionService, Fashion } from '../fashion.service';
import { CommonModule } from '@angular/common';

@Component({
  selector: 'app-fashion-view',
  standalone: true,
  imports: [CommonModule],
  template: `
    <div class="view-container">
      <div *ngIf="fashion" class="fashion-detail-view">
        <div class="view-header">
          <h2>{{ fashion.title }}</h2>
          <button class="btn-back" (click)="back()">← Back to List</button>
        </div>
        
        <div class="view-content">
          <div class="view-left">
            <img [src]="fashion.thumbnail" [alt]="fashion.title" class="detail-image" />
          </div>
          
          <div class="view-right">
            <div class="info-group">
              <label>Style:</label>
              <span class="badge">{{ fashion.style }}</span>
            </div>
            
            <div class="info-group">
              <label>Created:</label>
              <span>{{ fashion.createdAt | date: 'medium' }}</span>
            </div>
            
            <div class="info-group info-details">
              <label>Details:</label>
              <div class="details-content" [innerHTML]="fashion.details"></div>
            </div>
          </div>
        </div>
      </div>
      
      <div *ngIf="!fashion" class="no-data">
        <p>Loading...</p>
      </div>
    </div>
  `,
  styles: [`
    .view-container {
      padding: 20px;
      background: #f5f5f5;
      border-radius: 8px;
    }
    
    .fashion-detail-view {
      background: white;
      border-radius: 8px;
      overflow: hidden;
      box-shadow: 0 2px 8px rgba(0,0,0,0.1);
    }
    
    .view-header {
      display: flex;
      justify-content: space-between;
      align-items: center;
      padding: 20px;
      border-bottom: 2px solid #eee;
    }
    
    .view-header h2 {
      margin: 0;
      color: #333;
    }
    
    .btn-back {
      background: #6c757d;
      color: white;
      padding: 8px 16px;
      border: none;
      border-radius: 4px;
      cursor: pointer;
      font-weight: 600;
    }
    
    .btn-back:hover {
      background: #5a6268;
    }
    
    .view-content {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 30px;
      padding: 30px;
    }
    
    .view-left {
      text-align: center;
    }
    
    .detail-image {
      max-width: 100%;
      height: auto;
      border-radius: 8px;
      box-shadow: 0 2px 8px rgba(0,0,0,0.15);
    }
    
    .view-right {
      display: flex;
      flex-direction: column;
      gap: 20px;
    }
    
    .info-group {
      padding: 12px;
      background: #f9f9f9;
      border-radius: 4px;
    }
    
    .info-group label {
      display: block;
      font-weight: 600;
      color: #333;
      margin-bottom: 8px;
    }
    
    .badge {
      display: inline-block;
      background: #007bff;
      color: white;
      padding: 6px 16px;
      border-radius: 20px;
      font-size: 14px;
      font-weight: bold;
    }
    
    .info-details {
      grid-column: 1 / -1;
      padding: 20px;
    }
    
    .details-content {
      line-height: 1.6;
      color: #555;
    }
    
    .details-content p {
      margin-bottom: 12px;
    }
    
    .no-data {
      text-align: center;
      padding: 40px;
      color: #666;
    }
    
    @media (max-width: 768px) {
      .view-content {
        grid-template-columns: 1fr;
      }
      
      .view-header {
        flex-direction: column;
        gap: 10px;
        align-items: flex-start;
      }
    }
  `]
})
export class FashionViewComponent implements OnInit {
  fashion?: Fashion;

  constructor(
    private fashionService: FashionService,
    private route: ActivatedRoute,
    private router: Router
  ) {}

  ngOnInit() {
    const id = this.route.snapshot.paramMap.get('id');
    if (id) {
      this.fashionService.getFashion(id).subscribe(data => this.fashion = data);
    }
  }

  back() {
    this.router.navigate(['/fashions']);
  }
}
